def range_summary(nums):
    if not nums:
        return ''
    runs = []
    current_start, current_end = nums[0], nums[0]
    for num in nums:
        if num == current_end + 1:
            current_end = num
        else:
            runs.append((current_start, current_end))
            current_start, current_end = num, num
    runs.append((current_start, current_end))
    return ', '.join(f'{start}-{end}' if start != end else str(start) for start, end in runs)
